class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int ones = 0;
        for (int num : nums) {
            if (num == 1) ones++;
        }
        if (ones == 0) return 0;
        int minSwaps = Integer.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            int swaps = 0;
            for (int j = i; j < i + ones; j++) {
                if (nums[j % n] == 0) swaps++;
            }
            minSwaps = Math.min(minSwaps, swaps);
        }
        return minSwaps;
    }
}
